      "leftRail canvas rightRail"
      "statusbar statusbar statusbar"
    `,
    transition: 'grid-template-columns 200ms var(--ease-paper, ease)',
    height: '100dvh',
    width: '100%',
    overflow: 'hidden',
    background: 'var(--color-background)',
