        {leftCollapsed ? (leftRailCollapsed ?? null) : leftRail}
      </aside>
      <main
        aria-label={t('workspace.canvasLabel')}
        data-testid="app-shell-canvas"
        style={{ gridArea: 'canvas', minWidth: 0, minHeight: 0 }}
        className="relative overflow-hidden bg-background"
      >
        {canvas}
